const claude = $input.first().json;
const metadata = $('Extract Asset Metadata').first().json;

let assessment;
try {
  assessment = JSON.parse(claude.content[0].text);
} catch (e) {
  const match = claude.content[0].text.match(/\{[\s\S]*\}/);
  assessment = match ? JSON.parse(match[0]) : {
    quality_score: 5,
    visual_rating: 'fair',
    optimization_rating: 'fair',
    issues: ['Failed to parse assessment'],
    strengths: [],
    ready_for_production: false,
    recommended_improvements: []
  };
}

// Combine with technical metrics
const technical_score = 0;
if (metadata.poly_count_lod0 < 10000) technical_score += 3;
if (metadata.lod_count >= 3) technical_score += 2;

const final_score = Math.round((assessment.quality_score + technical_score) / 2);

return [{
  json: {
    asset_path: metadata.asset_path,
    asset_name: metadata.asset_name,
    quality_score: final_score,
    visual_rating: assessment.visual_rating,
    optimization_rating: assessment.optimization_rating,
    issues: assessment.issues.join('; '),
    strengths: assessment.strengths.join('; '),
    ready_for_production: assessment.ready_for_production && final_score >= 7,
    improvements: assessment.recommended_improvements.join('; '),
    reasoning: assessment.reasoning,
    poly_count: metadata.poly_count_lod0,
    lod_count: metadata.lod_count,
    assessed_at: new Date().toISOString()
  }
}];
